import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse(`{"title":"Ben's Bites — 2026-05-21","description":"","frontmatter":{"title":"Ben's Bites — 2026-05-21","date":"2026-05-21T00:00:00.000Z","source":"Ben's Bites","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-21-bens-bites.md","filePath":"research/ai-news/2026-05/2026-05-21-bens-bites.md","lastUpdated":1779796674000}`),n={name:"research/ai-news/2026-05/2026-05-21-bens-bites.md"};function s(i,e,l,h,p,u){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="🍔-ben-s-bites-—-2026-05-21" tabindex="-1">🍔 Ben&#39;s Bites — 2026-05-21 <a class="header-anchor" href="#🍔-ben-s-bites-—-2026-05-21" aria-label="Permalink to &quot;🍔 Ben&#39;s Bites — 2026-05-21&quot;">​</a></h1><blockquote><p>Ben Tossell 的 AI 日報，工具圈消息源 來源：<a href="https://www.bensbites.com/feed" target="_blank" rel="noreferrer">Ben&#39;s Bites</a></p></blockquote><hr><h2 id="can-i-get-my-agents-on-the-phone" tabindex="-1"><a href="https://www.bensbites.com/p/can-i-get-my-agents-on-the-phone" target="_blank" rel="noreferrer">Can I get my agents on the phone?</a> <a class="header-anchor" href="#can-i-get-my-agents-on-the-phone" aria-label="Permalink to &quot;[Can I get my agents on the phone?](https://www.bensbites.com/p/can-i-get-my-agents-on-the-phone)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-05-19</em></p><p>Hey folks</p><p><a href="https://blog.google/innovation-and-ai/technology/developers-tools/io-2026-save-the-date/" target="_blank" rel="noreferrer">Google I/O starts today</a>, and Logan tweeted: &quot;<a href="https://x.com/OfficialLoganK/status/2056107524802457887" target="_blank" rel="noreferrer">The model is the product</a>&quot;. There have been some rumours that the latest Gemini model scores similar on benchmarks to GPT 5.5 - but we&#39;ll see how it feels when actually using it - previous models also scored well but didn&#39;t feel great to work with.</p><p>When models are so good, harnesses will be much less important. I just don&#39;t think today is the day that happens. And on that point, the role of a harness will probably just shift - instead of managing how/which tools to use, the system prompt, context management etc it could be managed agents, sandboxing, cloud/local management.</p><p>I started using Codex on my phone…but not all that much to be honest. A lot of the agent harnesses these days have ways to control your sessions from your phone - Claude Code has /remote-control, Pi can build one for itself (i use a telegram one) and Droid has mobile web + Droid computers.</p><p>Most of my mobile first work at the moment is more brainstorming than building and I find myself flitting between all these options all the time.</p><p>I used to use my OpenClaw bot like an addict, but haven&#39;t spoken to the poor bastard for weeks now.</p><p>It may help that I&#39;m currently focused on just one (ish) main thing - this &#39;course&#39;. Which is really more of a library or reference manual on how I think about agents, how I steer them and build with them.</p><hr><p><em>Ben &#39;s Bites is brought to you by <strong><a href="https://hyperagent.com/founding500?utm_source=newsletter&amp;utm_medium=paidmedia&amp;utm_campaign=HA-BENSBITES" target="_blank" rel="noreferrer">Hyperagent from Airtable</a></strong></em></p><blockquote><p><em><a href="https://hyperagent.com/founding500?utm_source=newsletter&amp;utm_medium=paidmedia&amp;utm_campaign=HA-BENSBITES" target="_blank" rel="noreferrer">Hyperagent</a>, the cloud agent system with full computing environments, is giving $10M in inference credits to help founders build and run agent-first companies. The first 500 qualifying applicants gain access to this limited founder offer. <a href="https://hyperagent.com/founding500?utm_source=newsletter&amp;utm_medium=paidmedia&amp;utm_campaign=HA-BENSBITES" target="_blank" rel="noreferrer">Applications close May 31st</a>.</em></p></blockquote><hr><h4 id="headlines" tabindex="-1">Headlines <a class="header-anchor" href="#headlines" aria-label="Permalink to &quot;Headlines&quot;">​</a></h4><ul><li><p><strong><a href="https://openai.com/index/work-with-codex-from-anywhere/" target="_blank" rel="noreferrer">Codex now connects your Mac to your phone</a></strong>. You can start tasks in Codex from your phone, but the actual work still runs on your Mac, devbox or remote machine, i.e. files, setup and credentials stay where they are, while you can approve commands, answer questions, and review diffs from your phone. This update also brings Hooks to Codex.</p></li><li><p>Anthropic is <strong><a href="https://x.com/AnthropicAI/status/2056419620643541012" target="_blank" rel="noreferrer">acquiring Stainless</a></strong> , a platform to build SDKs (also used by OpenAI), and they are shutting the service down. Also, at their London conference, they added self-hosted sandboxes and MCP tunnels to <strong><a href="https://x.com/claudeai/status/2056645485696315581" target="_blank" rel="noreferrer">Claude Managed Agents</a></strong> - their &quot;running agents made easy&quot; product for companies.</p></li><li><p><strong><a href="https://blog.cloudflare.com/cyber-frontier-models/" target="_blank" rel="noreferrer">Cloudflare tested Anthropic&#39;s Mythos</a></strong> against 50 of its repos. Quick takeaways:</p><ul><li><p>Mythos is great at spotting real attacks, which are often many small vulnerabilities connected in a chain.</p></li><li><p>A single model, however smart, without a good harness leaves a lot to be found.</p></li><li><p>&quot;Find bugs fast and patch them faster&quot; is not a good idea. Teams need to focus on making bugs harder to chain (even if they exist) and to exploit.</p></li></ul></li><li><p><strong><a href="https://cursor.com/blog/composer-2-5" target="_blank" rel="noreferrer">Cursor&#39;s Composer 2.5</a></strong> (partly trained on SpaceX&#39;s GPUs) is out. The selective benchmarks that Cursor reports put the model roughly at the same place as Opus 4.7-xhigh and GPT-5.5-high, while being much cheaper than them.</p></li></ul><hr><p><a href="https://www.bensbites.com/subscribe" target="_blank" rel="noreferrer">Subscribe now</a></p><hr><h4 id="my-feed" tabindex="-1">My feed <a class="header-anchor" href="#my-feed" aria-label="Permalink to &quot;My feed&quot;">​</a></h4><ul><li><p>Two AI startups worth watching: <a href="https://x.com/skirano/status/2054975534539370708" target="_blank" rel="noreferrer">Magicpath (design canvas)</a> and <a href="https://www.raindrop.ai/workshop/" target="_blank" rel="noreferrer">Raindrop AI (monitoring agents in production)</a>, both of which are making their products usable by external coding agents like Claude Code or Codex.</p></li><li><p><a href="https://x.ai/cli" target="_blank" rel="noreferrer">Even Grok/xAI has a coding CLI now</a>. Let&#39;s see what Google does with Gemini CLI at I/O today.</p></li><li><p><a href="https://x.com/karrisaarinen/status/2054993293210259752" target="_blank" rel="noreferrer">Linear Agent</a> can now read the codebase directly to build a hypothesis, investigate support questions, find people who worked on a feature, and more.</p></li><li><p>Best practices for <a href="https://claude.com/blog/how-claude-code-works-in-large-codebases-best-practices-and-where-to-start" target="_blank" rel="noreferrer">running Claude Code at scale</a>.</p></li><li><p>Citadel&#39;s founder, Ken Griffin, one of the anti-AI hype people, is now saying that they are seeing <a href="https://youtu.be/Csjy_A3Kj9s?t=1319" target="_blank" rel="noreferrer">high-skilled jobs being &quot;automated&quot; by AI.</a></p></li><li><p><a href="https://browse.sh/" target="_blank" rel="noreferrer">Browse.sh</a> from Browserbase - open-source catalogue of skills/playbooks for agents to perform tasks on the internet.</p></li><li><p><a href="https://github.com/firstbatchxyz/watchmen" target="_blank" rel="noreferrer">Watchmen</a> - skill files your coding agents should already have from your past sessions. Local and open-source.</p></li><li><p><a href="https://x.com/cognition/status/2056396941181727210" target="_blank" rel="noreferrer">Devin Auto-Triage</a> monitors bugs, alerts and incidents, investigates them and comes back with context, next steps or a PR.</p></li><li><p><a href="https://x.com/JiaZhihao/status/2055327218415341978" target="_blank" rel="noreferrer">Motus Tracing</a> - open-source observability for AI agents.</p></li><li><p><a href="https://x.com/nozmen/status/2056396698688122910" target="_blank" rel="noreferrer">designmd.sh</a> - a public registry for DESIGN.md files, so agents can understand design systems from repos.</p></li><li><p><a href="https://jxnl.github.io/blog/writing/2026/05/10/codex-maxxing/" target="_blank" rel="noreferrer">Jason Liu on Codex maxxing</a> - daily primitives for durable threads, shared memory, and keeping Codex useful across a real workflow.</p></li><li><p><a href="https://buildwithtaste.com/product/mcp" target="_blank" rel="noreferrer">Taste MCP beta</a> - portable design preferences for Codex, Cursor, Claude Code, etc.</p></li><li><p>Claire Vo and Thariq on &quot;<a href="https://youtu.be/Qrpm7E80wQ0" target="_blank" rel="noreferrer">HTML is the new markdown</a>&quot; - using HTML artifacts as specs, micro-UIs, and human-readable agent context.</p></li><li><p><a href="https://x.com/brian_lovin/status/2056444390940516409" target="_blank" rel="noreferrer">Brian Lovin&#39;s Notion Worker</a> - syncs the people you follow on X into a Notion DB with optional AI enrichment.</p></li><li><p>Benedict Evans&#39; new &quot;<a href="https://www.ben-evans.com/presentations" target="_blank" rel="noreferrer">AI Is Eating The World</a>&quot; deck.</p></li><li><p>Coatue says its AI framework moved from &quot;follow the GPU&quot; to &quot;<a href="https://x.com/coatuemgmt/status/2055408437782290480" target="_blank" rel="noreferrer">follow the gigawatt</a>&quot;.</p></li></ul><hr><h4 id="afters" tabindex="-1">Afters <a class="header-anchor" href="#afters" aria-label="Permalink to &quot;Afters&quot;">​</a></h4><p><a href="https://www.bensbites.com/?utm_source=substack&amp;utm_medium=email&amp;utm_content=share&amp;action=share" target="_blank" rel="noreferrer">Share Ben&#39;s Bites</a></p><hr><ul><li><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p></li><li><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben&#39;s Bites</p></li><li><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p></li></ul><blockquote><h6 id="sponsors-who-make-this-newsletter-possible" tabindex="-1"><em>* sponsors who make this newsletter possible 😃</em> <a class="header-anchor" href="#sponsors-who-make-this-newsletter-possible" aria-label="Permalink to &quot;_* sponsors who make this newsletter possible :)_&quot;">​</a></h6><h6 id="wanna-partner-with-us-for-the-next-quarter" tabindex="-1"><em>Wanna partner with us for the next quarter?</em> <a class="header-anchor" href="#wanna-partner-with-us-for-the-next-quarter" aria-label="Permalink to &quot;_Wanna partner with us for the next quarter?_&quot;">​</a></h6><h6 id="email-us-atshanice-bensbites-com-or-k-bensbites-com" tabindex="-1"><em>Email us at<a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></em> <a class="header-anchor" href="#email-us-atshanice-bensbites-com-or-k-bensbites-com" aria-label="Permalink to &quot;_Email us at[shanice@bensbites.com](mailto:shanice@bensbites.com) or [k@bensbites.com](mailto:k@bensbites.com)_&quot;">​</a></h6></blockquote><p>Ben&#39;s Bites is a reader-supported publication. To receive new posts and support my work, consider becoming a free or paid subscriber.</p><hr><h2 id="agents-feedback-tip" tabindex="-1"><a href="https://www.bensbites.com/p/agents-feedback-tip" target="_blank" rel="noreferrer">Agents feedback tip</a> <a class="header-anchor" href="#agents-feedback-tip" aria-label="Permalink to &quot;[Agents feedback tip](https://www.bensbites.com/p/agents-feedback-tip)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-05-14</em></p><p>Hey folks, I&#39;m testing out something new in my building workflow…</p><p>When an agent asks for feedback it feels like the levels are</p><ol><li><p>type your response</p></li><li><p>voice-to-text your response</p></li><li><p>+ images to your feedback</p></li><li><p>get the agent to use the browser</p></li></ol><p>But I just started screen-recording and talking then giving that file to my agent</p><p><a href="https://substackcdn.com/image/fetch/$s_!Q4Fy!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F4b732846-79a5-4a45-b7a0-1cfc55a2918c_1458x448.png" target="_blank" rel="noreferrer"></a></p><p>This is me, in droid, like 30 mins ago. It pulls together a pretty great visual report you can easily review. I can navigate to other websites or apps and show what good looks like from other people, I can highlight specific points and it&#39;ll recreate those points with GIFs.</p><p>It gives itself an &#39;actions&#39; checklist underneath. And just feels great to have screenshot -&gt; my feedback -&gt; action for the agent.</p><p><a href="https://substackcdn.com/image/fetch/$s_!KXnE!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fda62482a-91c6-4d5c-86e0-9f7c5418b0ba_1596x1546.png" target="_blank" rel="noreferrer"></a></p><p>It&#39;s pretty great so far, and then I&#39;ve got these html files saved in my projects to always refer back to - will be good for a build log too.</p><p>Probably not great for the token conscious out there - and thinking about it, I could probably use ffmpeg to create actual clips of the video if I wanted. Agents read frames well though so it&#39;d be more for me if I did.</p><p>I turned it into a simple skill:</p><p>---</p><p>name: video-to-html</p><p>description: Use when the user wants you to convert their video into a structured HTML document.</p><p>---</p><p>Turn the user&#39;s video into a structured HTML document. Transcribe the video and pull out the keyframes linked to timestamps for important information. When the user is talking about something that is not dynamic, create short GIFs from the keyframes.</p><p>Let me know any cool use-cases or remixes of this 😊</p><hr><p><em>Ben &#39;s Bites is brought to you by <strong><a href="https://hyperagent.com/founding500?utm_source=newsletter&amp;utm_medium=paidmedia&amp;utm_campaign=HA-BENSBITES" target="_blank" rel="noreferrer">Hyperagent from Airtable</a></strong></em></p><blockquote><p><a href="https://hyperagent.com/founding500?utm_source=newsletter&amp;utm_medium=paidmedia&amp;utm_campaign=HA-BENSBITES" target="_blank" rel="noreferrer">Hyperagent</a>, the cloud agent system with full computing environments, is giving $10M in inference credits to help founders build and run agent-first companies. The first 500 qualifying applicants gain access to this limited founder offer. <a href="https://hyperagent.com/founding500?utm_source=newsletter&amp;utm_medium=paidmedia&amp;utm_campaign=HA-BENSBITES" target="_blank" rel="noreferrer">Applications close May 31st</a>.</p></blockquote><hr><h4 id="headlines-1" tabindex="-1">Headlines <a class="header-anchor" href="#headlines-1" aria-label="Permalink to &quot;Headlines&quot;">​</a></h4><ul><li><p><strong><a href="https://x.com/ClaudeDevs/status/2054610152817619388" target="_blank" rel="noreferrer">Your Claude plan is changing</a></strong> if you use third-party tools (like Conductor, Zed, Openclaw, T3 Code, etc.) with it.</p><ul><li><p>Separate limit for all such usage. Provided as extra monthly credits equal to the value of your plan.</p></li><li><p>No subsidised tokens, credits won&#39;t roll over and usage after you burn through these credits is billed at API rates.</p></li><li><p>Using Claude in Claude Code, Claude app, etc., stays the same and is separate from this.</p></li><li><p>Starts from June 15th, but they are increasing your <a href="https://x.com/ClaudeDevs/status/2054639777685934564" target="_blank" rel="noreferrer">weekly rate limits</a> by 50% for the next two months.</p></li></ul></li><li><p>Google announced some <strong>Gemini on Android</strong> updates before I/O - add features like auto-completing forms, rambling voice notes to clean text, and some app automations under the name &quot;<strong><a href="https://blog.google/products-and-platforms/platforms/android/gemini-intelligence/" target="_blank" rel="noreferrer">Gemini Intelligence</a></strong> &quot;. They also announced a new class of laptops called <strong><a href="https://blog.google/products-and-platforms/platforms/android/meet-googlebook" target="_blank" rel="noreferrer">Googlebooks</a></strong> , not to be confused with <a href="https://thenewthings.com/p/googlebooks-are-not-google-books" target="_blank" rel="noreferrer">Google Books</a>.</p></li><li><p><strong><a href="https://www.notion.com/product/dev" target="_blank" rel="noreferrer">Notion has a developer platform now</a></strong>. The biggest addition is a markdown API. Also, devs can sync outside data into Notion, build tools for Notion Agents, run code on Notion&#39;s infra, and eventually bring agents like Claude/Codex into Notion as teammates. But I think people who don&#39;t call them developers will use this.</p><ul><li>They also launched a CLI called <strong><a href="https://ntn.dev/" target="_blank" rel="noreferrer">ntn</a></strong>.</li></ul></li><li><p><strong><a href="https://vercel.com/blog/ai-gateway-production-index" target="_blank" rel="noreferrer">Vercel published an AI Gateway production index</a></strong> based on real usage across apps and agents. Anthropic leads spend (61% -- due to opus), Google leads token volume (38% -- due to flash), and agentic workloads are 59% of token usage. Most large teams route across many models instead of betting on one lab.</p></li></ul><hr><p><a href="https://www.bensbites.com/subscribe" target="_blank" rel="noreferrer">Subscribe now</a></p><hr><h4 id="my-feed-1" tabindex="-1">My feed <a class="header-anchor" href="#my-feed-1" aria-label="Permalink to &quot;My feed&quot;">​</a></h4><ul><li><p>Cursor now lets you run cloud agents inside a <a href="https://cursor.com/blog/cloud-agent-development-environments" target="_blank" rel="noreferrer">fully configured development environment</a>.</p></li><li><p><a href="http://github.com/stablyai/orca" target="_blank" rel="noreferrer">Orca</a> - Claude Code&#39;s agent view but for Codex, OpenCode, Droid and Pi.</p></li><li><p><a href="https://oboe.com/" target="_blank" rel="noreferrer">Oboe</a> - LLMs wrapped in a way that helps you learn.</p></li><li><p><a href="https://interfaces.dev/" target="_blank" rel="noreferrer">Interfaces.dev</a> - A monthly design engineering magazine about building great interfaces.</p></li><li><p><a href="https://x.com/patrick_oshag/status/2054532117410054252" target="_blank" rel="noreferrer">Anthropic CFO Krishna Rao</a> on compute allocation, pricing dynamics and model company economics:</p></li><li><p><a href="https://www.aiiq.org/" target="_blank" rel="noreferrer">AI IQ</a> - frontier AI models, scored on the human IQ scale.</p></li><li><p><a href="https://x.com/eoghan/status/2054238946612367818" target="_blank" rel="noreferrer">Intercom is rebranding</a> the entire company to Fin, their popular AI agent.</p></li><li><p><a href="https://executor.sh/home?try=local" target="_blank" rel="noreferrer">Executor</a> - Convert MCPs/OpenAPIs servers into code mode under the hood, 100% local on your device.</p></li><li><p>How OpenAI built a <a href="https://openai.com/index/building-codex-windows-sandbox/" target="_blank" rel="noreferrer">safe sandbox for Windows</a>.</p></li></ul><hr><h4 id="afters-1" tabindex="-1">Afters <a class="header-anchor" href="#afters-1" aria-label="Permalink to &quot;Afters&quot;">​</a></h4><p><a href="https://www.bensbites.com/?utm_source=substack&amp;utm_medium=email&amp;utm_content=share&amp;action=share" target="_blank" rel="noreferrer">Share Ben&#39;s Bites</a></p><hr><ul><li><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p></li><li><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben&#39;s Bites</p></li><li><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p></li></ul><blockquote><h6 id="sponsors-who-make-this-newsletter-possible-1" tabindex="-1"><em>* sponsors who make this newsletter possible 😃</em> <a class="header-anchor" href="#sponsors-who-make-this-newsletter-possible-1" aria-label="Permalink to &quot;_* sponsors who make this newsletter possible :)_&quot;">​</a></h6><h6 id="wanna-partner-with-us-for-the-next-quarter-1" tabindex="-1"><em>Wanna partner with us for the next quarter?</em> <a class="header-anchor" href="#wanna-partner-with-us-for-the-next-quarter-1" aria-label="Permalink to &quot;_Wanna partner with us for the next quarter?_&quot;">​</a></h6><h6 id="email-us-atshanice-bensbites-com-or-k-bensbites-com-1" tabindex="-1"><em>Email us at<a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></em> <a class="header-anchor" href="#email-us-atshanice-bensbites-com-or-k-bensbites-com-1" aria-label="Permalink to &quot;_Email us at[shanice@bensbites.com](mailto:shanice@bensbites.com) or [k@bensbites.com](mailto:k@bensbites.com)_&quot;">​</a></h6></blockquote><p>Ben&#39;s Bites is a reader-supported publication. To receive new posts and support my work, consider becoming a free or paid subscriber.</p><hr>',69)])])}const m=t(n,[["render",s]]);export{c as __pageData,m as default};
